# https://leetcode.cn/problems/number-of-paths-with-max-score/submissions/734129126/?envType=daily-question&envId=2026-07-05
from typing import List, Tuple, Optional
from heapq import heapify,heappop,heappush 

class Solution:
    def pathsWithMaxScore(self, board: List[str]) -> List[int]:
        m,n = len(board),len(board[0])
        dp = [[-10**10] *m for _ in range(n)]
        st = [(0,m-1,n-1)]
        board = [[a for a in arr] for arr in board]
        board[0][0]= "0" 
        board[-1][-1] = "0"
        dp[0][0] = 0
        for i in range(m):
            for j in range(n):
                if board[i][j] =="X":continue
                if i >0 and board[i-1][j] != "X":
                    dp[i][j] = max(dp[i][j], dp[i-1][j] + int(board[i][j]))
                if j >0 and board[i][j-1] != "X":
                    dp[i][j] = max(dp[i][j], dp[i][j-1] + int(board[i][j]))
                if i >0 and j >0 and board[i-1][j-1] != "X":
                    dp[i][j] = max(dp[i][j], dp[i-1][j-1] + int(board[i][j]))
        
        #print(dp)
        if dp[-1][-1] <0:
            return [0,0]
        
        dp2=[[0]*n for _ in range(m)]
        dp2[0][0] = 1 
        mod =10**9+7
        for i in range(m):
            for j in range(n):
                if dp[i][j] == -10**10: continue 
                dp2[i][j] %=mod
                if i < m-1 and dp[i+1][j] >=0 and  dp[i+1][j] == dp[i][j] +int(board[i+1][j]):
                    dp2[i+1][j] += dp2[i][j]
                if j < n-1 and dp[i][j+1] >=0 and  dp[i][j+1] == dp[i][j] +int(board[i][j+1]):
                    dp2[i][j+1] += dp2[i][j]
                if i < m-1 and j < n-1 and dp[i+1][j+1] >=0 and  dp[i+1][j+1] == dp[i][j] +int(board[i+1][j+1]):
                    dp2[i+1][j+1] += dp2[i][j]
        #print(dp,dp2)
        return [dp[-1][-1]  ,dp2[-1][-1]%mod]

